mapper.insert:

    SELECT FILE_ATTACH_SEQ.NEXTVAL FROM DUAL


INSERT INTO file_attach (file_no
                         , TARGET_TYPE
                         , TARGET_ID
                         , ORIGIN_NAME
                         , SAVED_NAME
                         , FILE_PATH
                         , REG_DATE)
VALUES (#{file_no}
        , #{targetType}
        , #{targetId}
        , #{originName}
        , #{savedName}
        , #{filePath}
        , SYSDATE)

mapper.select:
SELECT COUNT(*) AS fileCnt
FROM FILE_ATTACH
WHERE TARGET_ID = #{no}
